function stripCredentials(url) {
  const parsedUrl = new URL(url);
  const usernameRegex = /^([^:]+):/i;
  const passwordRegex = /:([^@]+)$/i;

  const usernameMatch = parsedUrl.username.match(usernameRegex);
  const passwordMatch = parsedUrl.password.match(passwordRegex);

  if (usernameMatch) {
    parsedUrl.username = usernameMatch[1];
  }

  if (passwordMatch) {
    parsedUrl.password = passwordMatch[1];
  }

  return parsedUrl.href;
}

