import os
import pickle
from typing import Dict

class IndexCache:
    def __init__(self, cache_dir: str):
        self.cache_dir = cache_dir
        os.makedirs(cache_dir, exist_ok=True)

    def get_cache_file(self, index_name: str) -> str:
        return os.path.join(self.cache_dir, f"{index_name}.cache")

    def load_cache(self, index_name: str) -> Dict:
        cache_file = self.get_cache_file(index_name)
        if os.path.exists(cache_file):
            with open(cache_file, "rb") as f:
                return pickle.load(f)
        return {}

    def save_cache(self, index_name: str, cache: Dict):
        cache_file = self.get_cache_file(index_name)
        with open(cache_file, "wb") as f:
            pickle.dump(cache, f)

